module top_module( 
					input wire signed  [31:0] PC,
					input wire signed  [31:0] Imm,
					output wire signed [31:0] PCimm
					);  wire _n01 = PC[0] ^ Imm[0];
  wire _c01 = PC[0] & Imm[0];
  wire _n02 = PC[1] ^ Imm[1] ^ _c01;
  wire _c02 = (PC[1] & Imm[1]) | (PC[1] & _c01) | (Imm[1] & _c01);
  wire _n03 = PC[2] ^ Imm[2] ^ _c02;
  wire _c03 = (PC[2] & Imm[2]) | (PC[2] & _c02) | (Imm[2] & _c02);
  wire _n04 = PC[3] ^ Imm[3] ^ _c03;
  wire _c04 = (PC[3] & Imm[3]) | (PC[3] & _c03) | (Imm[3] & _c03);
  assign PCimm = {_n01, _n02, _n03, _n04};
endmodule
